const { BREP } = api;

// Dish — round tray at the base.
const dish = BREP.label(BREP.cylinder(25, 4), 'dish');

// Dish lip — torus around the dish edge.
const lip = BREP.label(BREP.torus(24, 1.2).translate([0, 0, 2.5]), 'lip');

// Seed reservoir — revolved profile. Base lowered to z=3.5 so it overlaps the
// dish (z0..4) by 0.5mm instead of sitting flush on it.
const reservoir = BREP.label(
  BREP.revolve([
    [0, 3.5], [18, 3.5], [16, 12], [10, 30], [10, 40], [0, 40],
  ]),
  'reservoir',
);

// Roof — gazebo cap. Lowered to z=39 so its solid base overlaps the reservoir
// top (z=40) by 1mm (previously it floated at z=42 above a 2mm gap).
const roof = BREP.label(BREP.cone(22, 4, 18).translate([0, 0, 39]), 'roof');

// Roof spire — seated at z=56 so it overlaps the roof apex (top z=57).
const spire = BREP.label(BREP.cone(2, 0, 4).translate([0, 0, 56]), 'spire');

// Perches — radial rods at z=6. Each runs from r≈15 (embedded in the
// reservoir wall, r≈17 there) out to r≈28, so it fuses to the body instead
// of floating as a tangential bar at r=26.
const onePerch = BREP.cylinder(0.6, 13).rotate(90, [0, 1, 0]).translate([15, 0, 6]);
const perches = BREP.label(
  BREP.circularPattern(onePerch, 6, { radius: 0, axis: [0, 0, 1] }),
  'perch',
);

// Hanging hook — small torus around the spire (z=58) so it overlaps the
// spire (r≈1 there) and reads as a loop at the top.
const hook = BREP.label(BREP.torus(1.2, 0.5).translate([0, 0, 58]), 'hook');

return BREP.fuseAll([dish, lip, reservoir, roof, spire, perches, hook]);

